test("owner can create clinic pilot closeout and renewal handoff after payment collection", async () => {
  await withApp(async app => {
    const proof = await createPilotPaymentCollectionPacket(app);

    const supportDenied = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/payment-collections/${proof.paymentCollectionPacket.id}/closeout-packet`,
      headers: { cookie: proof.supportCookie },
      payload: { note: "Support cannot close out paid pilots." }
    });
    assert.equal(supportDenied.statusCode, 403);

    const created = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/payment-collections/${proof.paymentCollectionPacket.id}/closeout-packet`,
      headers: { cookie: proof.ownerCookie },
      payload: {
        note: "Owner closes first paid pilot and hands renewal to sales.",
        renewalDueDate: "2026-06-10"
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const packet = created.json().packet;
    assert.equal(packet.status, "closed-won-pilot");
    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.paymentCollectionPacketId, proof.paymentCollectionPacket.id);
    assert.equal(packet.postingPacketId, proof.postingPacket.id);
    assert.equal(packet.invoiceId, proof.invoice.id);
    assert.equal(packet.paymentId, proof.payment.id);
    assert.equal(packet.renewalTaskId, created.json().renewalTask.id);
    assert.equal(packet.invoiceNumber, "HHV-PILOT-2026-0001");
    assert.equal(packet.paymentReference, "ACBA-PILOT-2026-0001");
    assert.equal(packet.amount, 1704000);
    assert.equal(packet.periodKey, "2026-05");
    assert.equal(packet.renewalDueDate, "2026-06-10");
    assert.equal(packet.payload.kind, "armosphera-one-pilot-closeout-renewal-handoff");
    assert.equal(packet.payload.paymentCollection.id, proof.paymentCollectionPacket.id);
    assert.equal(packet.payload.paymentCollection.checksum, proof.paymentCollectionPacket.checksum);
    assert.equal(packet.payload.renewalTask.id, created.json().renewalTask.id);
    assert.equal(packet.payload.renewalTask.dueDate, "2026-06-10");
    assert.equal(packet.payload.renewalTask.sourceKey, `pilot-closeout-renewal:${proof.paymentCollectionPacket.id}`);
    assert.ok(packet.payload.controls.includes("paid-pilot-closeout-after-collection"));
    assert.ok(packet.payload.controls.includes("crm-renewal-task-created"));
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/payment-collections/${proof.paymentCollectionPacket.id}/closeout-packet`,
      headers: { cookie: proof.ownerCookie },
      payload: { renewalDueDate: "2026-06-10" }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().renewalTask.id, created.json().renewalTask.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/closeouts?paymentCollectionPacketId=${proof.paymentCollectionPacket.id}`,
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.ok(auditorList.json().packets.some(item => (
      item.id === packet.id
      && item.payload === undefined
      && item.renewalTaskId === created.json().renewalTask.id
      && item.renewalDueDate === "2026-06-10"
      && item.amount === 1704000
      && item.status === "closed-won-pilot"
    )));

    const customer360 = await app.inject({
      method: "GET",
      url: "/api/customer-360/cust-nare",
      headers: { cookie: proof.ownerCookie }
    });
    assert.equal(customer360.statusCode, 200, customer360.body);
    assert.ok(customer360.json().crm.tasks.some(task => (
      task.id === created.json().renewalTask.id
      && task.sourceKey === `pilot-closeout-renewal:${proof.paymentCollectionPacket.id}`
      && task.title.includes("Renew paid pilot")
    )));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: proof.ownerCookie },
      payload: { note: "Pilot closeout packet must be restore-scoped." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.pilot_closeout_packets.some(item => item.id === packet.id));
    assert.ok(backup.json().backup.payload.tables.crm_tasks.some(item => item.id === created.json().renewalTask.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: proof.ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.closeout.created"
      && event.details.packetId === packet.id
      && event.details.paymentCollectionPacketId === proof.paymentCollectionPacket.id
      && event.details.renewalTaskId === created.json().renewalTask.id
    )));
  });
});

test("sales can create clinic pilot renewal quote handoff from closeout", async () => {
  await withApp(async app => {
    const proof = await createPilotCloseoutPacket(app);

    const supportDenied = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/closeouts/${proof.closeoutPacket.id}/renewal-quote-handoff`,
      headers: { cookie: proof.supportCookie },
      payload: { note: "Support cannot issue renewal quote handoffs." }
    });
    assert.equal(supportDenied.statusCode, 403);

    const created = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/closeouts/${proof.closeoutPacket.id}/renewal-quote-handoff`,
      headers: { cookie: proof.salespersonCookie },
      payload: {
        validUntil: "2026-06-24",
        note: "Sales converts paid pilot closeout into monthly renewal quote."
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    const handoff = body.handoff;
    assert.equal(handoff.status, "renewal-quote-release-pending");
    assert.equal(handoff.templateKey, "clinic-wellness");
    assert.equal(handoff.closeoutPacketId, proof.closeoutPacket.id);
    assert.equal(handoff.paymentCollectionPacketId, proof.paymentCollectionPacket.id);
    assert.equal(handoff.renewalTaskId, proof.renewalTask.id);
    assert.equal(handoff.quoteId, body.quote.id);
    assert.equal(handoff.approvalId, body.approval.id);
    assert.equal(handoff.monthlyTotal, 960000);
    assert.equal(handoff.vat, 160000);
    assert.equal(handoff.subtotal, 800000);
    assert.equal(body.quote.status, "draft");
    assert.equal(body.quote.total, 960000);
    assert.equal(body.quote.vat, 160000);
    assert.equal(body.quote.subtotal, 800000);
    assert.equal(body.quote.validUntil, "2026-06-24");
    assert.equal(body.quote.lines.length, 1);
    assert.match(body.quote.lines[0].description, /monthly renewal/i);
    assert.equal(body.approval.actionKey, "crm.quote.release");
    assert.equal(body.approval.status, "pending");
    assert.equal(body.approval.payload.quoteId, body.quote.id);
    assert.equal(handoff.payload.kind, "armosphera-one-pilot-renewal-quote-handoff");
    assert.equal(handoff.payload.closeout.id, proof.closeoutPacket.id);
    assert.equal(handoff.payload.closeout.checksum, proof.closeoutPacket.checksum);
    assert.equal(handoff.payload.renewalTask.id, proof.renewalTask.id);
    assert.equal(handoff.payload.quote.total, 960000);
    assert.ok(handoff.payload.controls.includes("renewal-quote-release-approval-required"));
    assert.ok(handoff.payload.controls.includes("paid-pilot-closeout-checksum-linked"));
    assert.equal(sha256(JSON.stringify(handoff.payload)), handoff.checksum);

    const hiddenPublicQuote = await app.inject({
      method: "GET",
      url: `/api/public/quotes/${body.quote.publicToken}`
    });
    assert.equal(hiddenPublicQuote.statusCode, 404);

    const repeated = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/closeouts/${proof.closeoutPacket.id}/renewal-quote-handoff`,
      headers: { cookie: proof.salespersonCookie },
      payload: { validUntil: "2026-06-24" }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().handoff.id, handoff.id);
    assert.equal(repeated.json().quote.id, body.quote.id);
    assert.equal(repeated.json().approval.id, body.approval.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/renewal-quotes?closeoutPacketId=${proof.closeoutPacket.id}`,
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.ok(auditorList.json().handoffs.some(item => (
      item.id === handoff.id
      && item.payload === undefined
      && item.closeoutPacketId === proof.closeoutPacket.id
      && item.quoteId === body.quote.id
      && item.approvalId === body.approval.id
      && item.monthlyTotal === 960000
      && item.status === "renewal-quote-release-pending"
    )));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: proof.ownerCookie },
      payload: { note: "Pilot renewal quote handoff must be restore-scoped." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.pilot_renewal_quote_handoff_packets.some(item => item.id === handoff.id));
    assert.ok(backup.json().backup.payload.tables.quotes.some(item => item.id === body.quote.id));
    assert.ok(backup.json().backup.payload.tables.workflow_approvals.some(item => item.id === body.approval.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: proof.ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.renewal_quote_handoff.created"
      && event.details.handoffId === handoff.id
      && event.details.closeoutPacketId === proof.closeoutPacket.id
      && event.details.quoteId === body.quote.id
      && event.details.approvalId === body.approval.id
    )));
  });
});

test("sales can create clinic pilot renewal quote release packet after workflow executes", async () => {
  await withApp(async app => {
    const proof = await createPilotRenewalQuoteHandoff(app);

    const supportDenied = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quotes/${proof.renewalQuoteHandoff.id}/release-packet`,
      headers: { cookie: proof.supportCookie },
      payload: { note: "Support cannot release renewal quotes." }
    });
    assert.equal(supportDenied.statusCode, 403);

    const premature = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quotes/${proof.renewalQuoteHandoff.id}/release-packet`,
      headers: { cookie: proof.salespersonCookie },
      payload: { note: "Renewal release evidence waits for owner approval execution." }
    });
    assert.equal(premature.statusCode, 409);

    const decision = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${proof.renewalQuoteApproval.id}/decision`,
      headers: { cookie: proof.ownerCookie },
      payload: { decision: "approved", note: "Owner approved clinic monthly renewal quote release." }
    });
    assert.equal(decision.statusCode, 200, decision.body);

    const execution = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${proof.renewalQuoteApproval.id}/execute`,
      headers: { cookie: proof.ownerCookie }
    });
    assert.equal(execution.statusCode, 200, execution.body);
    assert.equal(execution.json().run.resultType, "crm_quote_release");
    assert.equal(execution.json().quote.id, proof.renewalQuote.id);
    assert.equal(execution.json().quote.status, "sent");

    const publicQuote = await app.inject({ method: "GET", url: `/api/public/quotes/${proof.renewalQuote.publicToken}` });
    assert.equal(publicQuote.statusCode, 200, publicQuote.body);
    assert.equal(publicQuote.json().quote.id, proof.renewalQuote.id);
    assert.equal(publicQuote.json().quote.total, 960000);

    const created = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quotes/${proof.renewalQuoteHandoff.id}/release-packet`,
      headers: { cookie: proof.salespersonCookie },
      payload: { note: "Monthly renewal quote public release evidence." }
    });
    assert.equal(created.statusCode, 200, created.body);
    const packet = created.json().packet;
    assert.equal(packet.status, "released");
    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.renewalQuoteHandoffId, proof.renewalQuoteHandoff.id);
    assert.equal(packet.closeoutPacketId, proof.closeoutPacket.id);
    assert.equal(packet.paymentCollectionPacketId, proof.paymentCollectionPacket.id);
    assert.equal(packet.renewalTaskId, proof.renewalTask.id);
    assert.equal(packet.quoteId, proof.renewalQuote.id);
    assert.equal(packet.approvalId, proof.renewalQuoteApproval.id);
    assert.equal(packet.total, 960000);
    assert.equal(packet.vat, 160000);
    assert.equal(packet.subtotal, 800000);
    assert.equal(packet.payload.kind, "armosphera-one-pilot-renewal-quote-release");
    assert.equal(packet.payload.handoff.id, proof.renewalQuoteHandoff.id);
    assert.equal(packet.payload.handoff.checksum, proof.renewalQuoteHandoff.checksum);
    assert.equal(packet.payload.closeout.id, proof.closeoutPacket.id);
    assert.equal(packet.payload.closeout.checksum, proof.closeoutPacket.checksum);
    assert.equal(packet.payload.renewalTask.id, proof.renewalTask.id);
    assert.equal(packet.payload.quote.id, proof.renewalQuote.id);
    assert.equal(packet.payload.quote.status, "sent");
    assert.equal(packet.payload.quote.total, 960000);
    assert.equal(packet.payload.quote.publicToken, proof.renewalQuote.publicToken);
    assert.equal(packet.payload.publicAvailability, true);
    assert.ok(packet.payload.controls.includes("owner-approved-renewal-quote-release"));
    assert.ok(packet.payload.controls.includes("public-renewal-quote-visible-after-workflow-execution"));
    assert.ok(packet.payload.controls.includes("renewal-quote-handoff-checksum-linked"));
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quotes/${proof.renewalQuoteHandoff.id}/release-packet`,
      headers: { cookie: proof.salespersonCookie },
      payload: { note: "Monthly renewal quote public release evidence." }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/renewal-quote-releases?renewalHandoffId=${proof.renewalQuoteHandoff.id}`,
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.ok(auditorList.json().packets.some(item => (
      item.id === packet.id
      && item.payload === undefined
      && item.renewalQuoteHandoffId === proof.renewalQuoteHandoff.id
      && item.quoteId === proof.renewalQuote.id
      && item.approvalId === proof.renewalQuoteApproval.id
      && item.status === "released"
    )));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: proof.ownerCookie },
      payload: { note: "Pilot renewal quote release packet must be restore-scoped." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.pilot_renewal_quote_release_packets.some(item => item.id === packet.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: proof.ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.renewal_quote_release.created"
      && event.details.packetId === packet.id
      && event.details.handoffId === proof.renewalQuoteHandoff.id
      && event.details.closeoutPacketId === proof.closeoutPacket.id
      && event.details.quoteId === proof.renewalQuote.id
      && event.details.approvalId === proof.renewalQuoteApproval.id
    )));
  });
});

test("accountant can hand accepted renewal quote into HayHashvapah invoice approval", async () => {
  await withApp(async app => {
    const proof = await createPilotRenewalQuoteReleasePacket(app);

    const supportDenied = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quote-releases/${proof.renewalQuoteReleasePacket.id}/acceptance-handoff`,
      headers: { cookie: proof.supportCookie },
      payload: { note: "Support cannot prepare renewal HayHashvapah invoice handoff." }
    });
    assert.equal(supportDenied.statusCode, 403);

    const premature = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quote-releases/${proof.renewalQuoteReleasePacket.id}/acceptance-handoff`,
      headers: { cookie: proof.accountantCookie },
      payload: { note: "Renewal accounting handoff must wait for customer acceptance." }
    });
    assert.equal(premature.statusCode, 409);

    const accepted = await app.inject({
      method: "POST",
      url: `/api/public/quotes/${proof.renewalQuote.publicToken}/accept`,
      payload: {
        signerName: "Nare Clinic Owner",
        signerEmail: "owner@nareclinic.am",
        acceptedAt: "2026-05-28"
      }
    });
    assert.equal(accepted.statusCode, 200, accepted.body);
    const acceptedBody = accepted.json();
    assert.equal(acceptedBody.quote.id, proof.renewalQuote.id);
    assert.equal(acceptedBody.quote.status, "accepted");
    assert.equal(acceptedBody.quote.total, 960000);
    assert.equal(acceptedBody.acceptance.signerEmail, "owner@nareclinic.am");
    assert.equal(acceptedBody.approval.actionKey, "finance.invoice.propose");
    assert.equal(acceptedBody.approval.status, "pending");
    assert.equal(acceptedBody.approval.payload.quoteId, proof.renewalQuote.id);
    assert.equal(acceptedBody.approval.payload.periodKey, "2026-05");
    assert.equal(acceptedBody.approval.payload.vatMode, "amd-inclusive-20");

    const created = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quote-releases/${proof.renewalQuoteReleasePacket.id}/acceptance-handoff`,
      headers: { cookie: proof.accountantCookie },
      payload: { note: "Customer accepted renewal; prepare HayHashvapah monthly invoice approval review." }
    });
    assert.equal(created.statusCode, 200, created.body);
    const packet = created.json().packet;
    assert.equal(packet.status, "renewal-invoice-approval-pending");
    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.renewalQuoteReleasePacketId, proof.renewalQuoteReleasePacket.id);
    assert.equal(packet.renewalQuoteHandoffId, proof.renewalQuoteHandoff.id);
    assert.equal(packet.closeoutPacketId, proof.closeoutPacket.id);
    assert.equal(packet.paymentCollectionPacketId, proof.paymentCollectionPacket.id);
    assert.equal(packet.renewalTaskId, proof.renewalTask.id);
    assert.equal(packet.quoteId, proof.renewalQuote.id);
    assert.equal(packet.acceptanceId, acceptedBody.acceptance.id);
    assert.equal(packet.financeApprovalId, acceptedBody.approval.id);
    assert.equal(packet.total, 960000);
    assert.equal(packet.vat, 160000);
    assert.equal(packet.subtotal, 800000);
    assert.equal(packet.payload.kind, "armosphera-one-pilot-renewal-quote-acceptance-hayhashvapah-handoff");
    assert.equal(packet.payload.release.id, proof.renewalQuoteReleasePacket.id);
    assert.equal(packet.payload.release.checksum, proof.renewalQuoteReleasePacket.checksum);
    assert.equal(packet.payload.handoff.id, proof.renewalQuoteHandoff.id);
    assert.equal(packet.payload.handoff.checksum, proof.renewalQuoteHandoff.checksum);
    assert.equal(packet.payload.closeout.id, proof.closeoutPacket.id);
    assert.equal(packet.payload.closeout.checksum, proof.closeoutPacket.checksum);
    assert.equal(packet.payload.renewalTask.id, proof.renewalTask.id);
    assert.equal(packet.payload.acceptance.signerEmail, "owner@nareclinic.am");
    assert.equal(packet.payload.quote.status, "accepted");
    assert.equal(packet.payload.quote.total, 960000);
    assert.equal(packet.payload.financeApproval.id, acceptedBody.approval.id);
    assert.equal(packet.payload.financeApproval.actionKey, "finance.invoice.propose");
    assert.equal(packet.payload.hayhashvapah.periodKey, "2026-05");
    assert.equal(packet.payload.hayhashvapah.vatMode, "amd-inclusive-20");
    assert.ok(packet.payload.controls.includes("public-renewal-quote-accepted-before-invoice-handoff"));
    assert.ok(packet.payload.controls.includes("owner-approval-required-before-renewal-hayhashvapah-draft"));
    assert.ok(packet.payload.controls.includes("renewal-quote-release-checksum-linked"));
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/renewal-quote-releases/${proof.renewalQuoteReleasePacket.id}/acceptance-handoff`,
      headers: { cookie: proof.accountantCookie },
      payload: { note: "Customer accepted renewal; prepare HayHashvapah monthly invoice approval review." }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/renewal-acceptance-handoffs?renewalQuoteReleasePacketId=${proof.renewalQuoteReleasePacket.id}`,
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.ok(auditorList.json().packets.some(item => (
      item.id === packet.id
      && item.payload === undefined
      && item.renewalQuoteReleasePacketId === proof.renewalQuoteReleasePacket.id
      && item.acceptanceId === acceptedBody.acceptance.id
      && item.financeApprovalId === acceptedBody.approval.id
      && item.periodKey === "2026-05"
      && item.vatMode === "amd-inclusive-20"
      && item.status === "renewal-invoice-approval-pending"
    )));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: proof.ownerCookie },
      payload: { note: "Pilot renewal acceptance handoff must be restore-scoped." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.pilot_renewal_quote_acceptance_handoff_packets.some(item => item.id === packet.id));
    assert.ok(backup.json().backup.payload.tables.quote_acceptances.some(item => item.id === acceptedBody.acceptance.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: proof.ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.renewal_quote_acceptance_handoff.created"
      && event.details.packetId === packet.id
      && event.details.releasePacketId === proof.renewalQuoteReleasePacket.id
      && event.details.handoffId === proof.renewalQuoteHandoff.id
      && event.details.acceptanceId === acceptedBody.acceptance.id
      && event.details.financeApprovalId === acceptedBody.approval.id
    )));
  });
});

