    assert.equal(handoff.nextRenewalQuoteReleasePacketId, proof.nextRenewalQuoteReleasePacket.id);
    assert.equal(handoff.nextRenewalQuoteHandoffId, proof.nextRenewalQuoteHandoff.id);
    assert.equal(handoff.renewalCloseoutPacketId, proof.renewalCloseoutPacket.id);
    assert.equal(handoff.renewalPaymentCollectionPacketId, proof.renewalPaymentCollectionPacket.id);
