    assert.equal(handoff.renewalQuoteHandoffId, proof.renewalQuoteHandoff.id);
    assert.equal(handoff.closeoutPacketId, proof.closeoutPacket.id);
    assert.equal(handoff.priorPaymentCollectionPacketId, proof.paymentCollectionPacket.id);
    assert.equal(handoff.priorPostingPacketId, proof.postingPacket.id);
    assert.equal(handoff.renewalTaskId, proof.renewalTask.id);
    assert.equal(handoff.nextRenewalTaskId, proof.nextRenewalTask.id);
    assert.equal(handoff.followingRenewalTaskId, proof.followingRenewalTask.id);
    assert.equal(handoff.quoteId, body.quote.id);
    assert.equal(handoff.approvalId, body.approval.id);
    assert.equal(handoff.monthlyTotal, 960000);
