    assert.equal(handoff.subtotal, 800000);
    assert.equal(body.quote.status, "draft");
    assert.equal(body.quote.total, 960000);
    assert.equal(body.quote.vat, 160000);
    assert.equal(body.quote.subtotal, 800000);
    assert.equal(body.quote.validUntil, "2026-08-12");
