      event.type === "pilot.continuation_renewal_hayhashvapah_draft_invoice.created"
      && event.details.packetId === packet.id
      && event.details.continuationRenewalAcceptanceHandoffId === proof.continuationRenewalAcceptanceHandoff.id
      && event.details.continuationRenewalQuoteReleasePacketId === proof.continuationRenewalQuoteReleasePacket.id
      && event.details.continuationRenewalQuoteHandoffId === proof.continuationRenewalQuoteHandoff.id
      && event.details.subsequentRenewalCloseoutPacketId === proof.subsequentRenewalCloseoutPacket.id
      && event.details.continuationRenewalTaskId === proof.continuationRenewalTask.id
      && event.details.acceptanceId === proof.continuationRenewalAcceptance.id
      && event.details.financeApprovalId === proof.continuationRenewalFinanceApproval.id
