    assert.ok(backup.json().backup.payload.tables.pilot_ongoing_renewal_quote_release_packets.some(item => item.id === packet.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: proof.ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.ongoing_renewal_quote_release.created"
      && event.details.packetId === packet.id
      && event.details.handoffId === proof.ongoingRenewalQuoteHandoff.id
      && event.details.continuationRenewalCloseoutPacketId === proof.continuationRenewalCloseoutPacket.id
      && event.details.ongoingRenewalTaskId === proof.ongoingRenewalTask.id
      && event.details.quoteId === proof.ongoingRenewalQuote.id
      && event.details.approvalId === proof.ongoingRenewalQuoteApproval.id
    )));
