    assert.equal(packet.invoiceNumber, "HHV-NEXT-ONGOING-RENEWAL-2026-0001");
    assert.equal(packet.paymentReference, "ACBA-NEXT-ONGOING-RENEWAL-2026-0001");
    assert.equal(packet.amount, 960000);
    assert.equal(packet.subtotal, 800000);
    assert.equal(packet.vat, 160000);
    assert.equal(packet.periodKey, "2026-11");
    assert.equal(packet.vatMode, "amd-inclusive-20");
    assert.equal(packet.closeoutDate, "2026-11-29");
    assert.equal(packet.followingOngoingRenewalDueDate, "2026-12-29");
    assert.equal(packet.payload.kind, "armosphera-one-pilot-next-ongoing-renewal-closeout");
    assert.equal(packet.payload.nextOngoingRenewalPaymentCollection.id, proof.nextOngoingRenewalPaymentCollectionPacket.id);
    assert.equal(packet.payload.nextOngoingRenewalPaymentCollection.checksum, proof.nextOngoingRenewalPaymentCollectionPacket.checksum);
