    assert.equal(packet.payload.release.id, proof.nextOngoingRenewalQuoteReleasePacket.id);
    assert.equal(packet.payload.handoff.id, proof.nextOngoingRenewalQuoteHandoff.id);
    assert.equal(packet.payload.ongoingRenewalCloseout.id, proof.ongoingRenewalCloseoutPacket.id);
    assert.equal(packet.payload.ongoingRenewalCloseout.checksum, proof.ongoingRenewalCloseoutPacket.checksum);
    assert.equal(packet.payload.ongoingRenewalPaymentCollection.id, proof.ongoingRenewalPaymentCollectionPacket.id);
    assert.equal(packet.payload.ongoingRenewalPaymentCollection.checksum, proof.ongoingRenewalPaymentCollectionPacket.checksum);
    assert.equal(packet.payload.nextOngoingRenewalTask.id, proof.nextOngoingRenewalTask.id);
