    assert.equal(packet.payload.followingOngoingRenewalTask.id, followingOngoingRenewalTask.id);
    assert.equal(packet.payload.followingOngoingRenewalTask.dueDate, "2026-12-29");
    assert.equal(packet.payload.followingOngoingRenewalTask.sourceKey, `pilot-next-ongoing-renewal-closeout-following:${proof.nextOngoingRenewalPaymentCollectionPacket.id}`);
    assert.equal(packet.payload.invoice.id, proof.nextOngoingRenewalInvoice.id);
