    assert.equal(packet.payload.payment.id, proof.nextOngoingRenewalPayment.id);
    assert.equal(packet.payload.payment.reference, "ACBA-NEXT-ONGOING-RENEWAL-2026-0001");
    assert.ok(packet.payload.controls.includes("next-ongoing-renewal-payment-confirmed-before-closeout"));
