    assert.ok(packet.payload.controls.includes("following-ongoing-renewal-official-posting-checksum-linked"));
    assert.ok(packet.payload.controls.includes("crm-subsequent-ongoing-renewal-task-created"));
    assert.ok(packet.payload.controls.includes("ready-for-subsequent-ongoing-renewal-quote-cycle"));
