    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().subsequentOngoingRenewalTask.id, subsequentOngoingRenewalTask.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/following-ongoing-renewal-closeouts?paymentCollectionPacketId=${proof.followingOngoingRenewalPaymentCollectionPacket.id}`,
      headers: { cookie: auditorCookie }
    });
