    assert.equal(packet.followingOngoingRenewalAcceptanceHandoffId, proof.followingOngoingRenewalAcceptanceHandoff.id);
    assert.equal(packet.followingOngoingRenewalQuoteReleasePacketId, proof.followingOngoingRenewalQuoteReleasePacket.id);
