    assert.ok(backup.json().backup.payload.tables.pilot_subsequent_ongoing_renewal_quote_release_packets.some(item => item.id === packet.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: proof.ownerCookie } });
