    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.subsequentOngoingRenewalAcceptanceHandoffId, proof.subsequentOngoingRenewalAcceptanceHandoff.id);
    assert.equal(packet.subsequentOngoingRenewalQuoteReleasePacketId, proof.subsequentOngoingRenewalQuoteReleasePacket.id);
    assert.equal(packet.subsequentOngoingRenewalQuoteHandoffId, proof.subsequentOngoingRenewalQuoteHandoff.id);
    assert.equal(packet.followingOngoingRenewalCloseoutPacketId, proof.followingOngoingRenewalCloseoutPacket.id);
