    assert.equal(created.statusCode, 200, created.body);
    const packet = created.json().packet;
    assert.equal(packet.status, "next-recurring-ongoing-renewal-official-invoice-open");
    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.nextRecurringOngoingRenewalDraftPacketId, proof.nextRecurringOngoingRenewalDraftPacket.id);
    assert.equal(packet.nextRecurringOngoingRenewalAcceptanceHandoffId, proof.nextRecurringOngoingRenewalAcceptanceHandoff.id);
    assert.equal(packet.nextRecurringOngoingRenewalQuoteReleasePacketId, proof.nextRecurringOngoingRenewalQuoteReleasePacket.id);
