    assert.equal(body.explanation.accountantReviewStatus, "accountant-review-required");
    assert.equal(body.explanation.modelPolicy, "deterministic-grounded-overdue-invoice");
    assert.ok(body.explanation.confidence >= 80);
    assert.ok(["medium", "high"].includes(body.explanation.riskLevel));
    assert.ok(body.explanation.summary.includes("HHV-1007"));
    assert.ok(body.explanation.summary.includes("Նարե Բժշկական Կենտրոն"));
    assert.ok(body.explanation.suggestedFollowUp.includes("HayHashvapah"));
    assert.ok(body.explanation.nextActions.some(action => /payment promise|collection/i.test(action)));
    assert.ok(body.explanation.groundingSources.some(source => source.type === "finance_invoice"));
    assert.ok(body.explanation.groundingSources.some(source => source.type === "receivables_aging"));
    assert.ok(body.explanation.groundingSources.some(source => source.type === "crm_task"));
    assert.ok(body.explanation.groundingSources.some(source => source.type === "customer_profile"));
    assert.match(body.explanation.checksum, /^[a-f0-9]{64}$/);
