    assert.equal(body.question.riskLevel, "legal");
    assert.equal(body.question.status, "pending-review");
    assert.equal(body.answer.reviewRequired, true);
    assert.ok(body.answer.confidence >= 80);
    assert.match(body.answer.answer, /HayHashvapah/);
    assert.ok(body.sources.some(source => source.id === "law-tax-code" && source.relevance >= 90));
    assert.equal(body.approval.actionKey, "legal.answer.approve");
    assert.equal(body.approval.riskLevel, "legal");
    assert.equal(body.approval.status, "pending");
    assert.equal(body.approval.customerId, "cust-nare");
    assert.equal(body.approval.payload.questionId, body.question.id);
    assert.equal(body.approval.payload.answerId, body.answer.id);
