test("approved privacy request creates idempotent customer data export packet", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    await reviewPersonalDataSource(app, cookie);

    const created = await app.inject({
      method: "POST",
      url: "/api/privacy/requests",
      headers: { cookie },
      payload: {
        customerId: "cust-ani",
        requestType: "export",
        requesterEmail: "owner@anibeauty.am",
        channel: "Telegram",
        note: "Customer asks for her appointment and consent data export."
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    assert.equal(body.request.customerId, "cust-ani");
    assert.equal(body.request.requestType, "export");
    assert.equal(body.request.status, "pending-approval");
    assert.equal(body.request.legalSourceId, "law-personal-data");
    assert.equal(body.approval.actionKey, "privacy.request.approve");
    assert.equal(body.approval.riskLevel, "legal");
    assert.equal(body.approval.payload.requestId, body.request.id);
    assert.ok(body.events.some(event => event.eventType === "privacy.request.created"));
    assert.ok(body.events.some(event => event.eventType === "workflow.approval.requested"));

    const decision = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${body.approval.id}/decision`,
      headers: { cookie },
      payload: { decision: "approved", note: "Owner approved export after source review" }
    });
    assert.equal(decision.statusCode, 200, decision.body);

    const executed = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${body.approval.id}/execute`,
      headers: { cookie }
    });
    assert.equal(executed.statusCode, 200, executed.body);
    const executedBody = executed.json();
    assert.equal(executedBody.idempotent, false);
    assert.equal(executedBody.run.resultType, "privacy_export_packet");
    assert.equal(executedBody.packet.customerId, "cust-ani");
    assert.equal(executedBody.packet.requestId, body.request.id);
    assert.equal(executedBody.packet.legalSourceId, "law-personal-data");
    assert.equal(executedBody.packet.status, "fulfilled");
    assert.match(executedBody.packet.checksum, /^[a-f0-9]{64}$/);
    assert.equal(executedBody.packet.payload.customer.taxId, "01888999");
    assert.equal(executedBody.packet.payload.profile.consentStatus, "consent-review-required");
    assert.ok(executedBody.packet.payload.profileSources.some(source => source.sourceApp === "campaigns"));
    assert.ok(executedBody.packet.payload.legalSource.status === "active");
    assert.ok(executedBody.events.some(event => event.eventType === "privacy.export_packet.created"));
    assert.ok(executedBody.events.some(event => event.eventType === "workflow.action.executed"));

    const repeated = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${body.approval.id}/execute`,
      headers: { cookie }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().idempotent, true);
    assert.equal(repeated.json().packet.id, executedBody.packet.id);

    const listed = await app.inject({ method: "GET", url: "/api/privacy/requests?customerId=cust-ani", headers: { cookie } });
    assert.equal(listed.statusCode, 200, listed.body);
    assert.ok(listed.json().requests.some(request => request.id === body.request.id && request.status === "fulfilled"));

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-ani", headers: { cookie } });
    const customer = customer360.json();
    assert.ok(customer.privacy.requests.some(request => request.id === body.request.id && request.status === "fulfilled"));
    assert.ok(customer.privacy.exportPackets.some(packet => packet.id === executedBody.packet.id));
    assert.ok(customer.timeline.some(event => event.eventType === "privacy.export_packet.created"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.ok(audit.json().events.some(event => event.type === "privacy.export_packet.created" && event.details.packetId === executedBody.packet.id));
  });
});

