test("draft CRM quote requires governed approval before public release", async () => {
  await withApp(async app => {
    const salesCookie = await login(app, "sales@armosphera.local");
    const ownerCookie = await login(app);
    const created = await app.inject({
      method: "POST",
      url: "/api/crm/quotes",
      headers: { cookie: salesCookie },
      payload: {
        customerId: "cust-van",
        dealId: "deal-van-season",
        title: "Tour booking automation launch",
        validUntil: "2026-06-30",
        lines: [
          { description: "Booking form and WhatsApp follow-up setup", quantity: 1, unitPrice: 480000 },
          { description: "HayHashvapah invoice handoff checklist", quantity: 1, unitPrice: 240000 }
        ]
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const quote = created.json().quote;
    assert.equal(quote.status, "draft");
    assert.equal(quote.total, 720000);
    assert.equal(quote.vat, 120000);
    assert.equal(quote.lines.length, 2);

    const hiddenPublic = await app.inject({ method: "GET", url: `/api/public/quotes/${quote.publicToken}` });
    assert.equal(hiddenPublic.statusCode, 404);

    const requested = await app.inject({
      method: "POST",
      url: `/api/crm/quotes/${quote.id}/request-approval`,
      headers: { cookie: salesCookie },
      payload: { note: "Customer-facing quote should be checked before public release." }
    });
    assert.equal(requested.statusCode, 200, requested.body);
    const approval = requested.json().approval;
    assert.equal(approval.actionKey, "crm.quote.release");
    assert.equal(approval.status, "pending");
    assert.equal(approval.customerId, "cust-van");
    assert.equal(approval.payload.quoteId, quote.id);
    assert.equal(approval.payload.total, 720000);

    const duplicate = await app.inject({
      method: "POST",
      url: `/api/crm/quotes/${quote.id}/request-approval`,
      headers: { cookie: salesCookie },
      payload: { note: "Do not create a second approval." }
    });
    assert.equal(duplicate.statusCode, 200, duplicate.body);
    assert.equal(duplicate.json().approval.id, approval.id);
    assert.equal(duplicate.json().idempotent, true);

    const decided = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${approval.id}/decision`,
      headers: { cookie: ownerCookie },
      payload: { decision: "approved", note: "Owner approved public quote release." }
    });
    assert.equal(decided.statusCode, 200, decided.body);

    const executed = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${approval.id}/execute`,
      headers: { cookie: ownerCookie }
    });
    assert.equal(executed.statusCode, 200, executed.body);
    const body = executed.json();
    assert.equal(body.run.resultType, "crm_quote_release");
    assert.equal(body.quote.status, "sent");
    assert.equal(body.quote.sentAt.length > 0, true);
    assert.equal(body.approval.status, "executed");

    const publicQuote = await app.inject({ method: "GET", url: `/api/public/quotes/${quote.publicToken}` });
    assert.equal(publicQuote.statusCode, 200, publicQuote.body);
    assert.equal(publicQuote.json().quote.id, quote.id);
    assert.equal(publicQuote.json().quote.status, "sent");

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-van", headers: { cookie: salesCookie } });
    assert.ok(customer360.json().crm.quotes.some(item => item.id === quote.id && item.status === "sent"));
    assert.ok(customer360.json().workflowRuns.some(run => run.resultType === "crm_quote_release" && run.resultId === quote.id));
    assert.ok(customer360.json().timeline.some(event => event.eventType === "crm.quote.released"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => event.type === "crm.quote.created" && event.details.quoteId === quote.id));
    assert.ok(audit.json().events.some(event => event.type === "crm.quote.release.requested" && event.details.quoteId === quote.id));
    assert.ok(audit.json().events.some(event => event.type === "crm.quote.released" && event.details.quoteId === quote.id));
  });
});

