test("quote acceptance delivers signed quote and deal webhooks", async () => {
  await withWebhookReceiver(async receiver => {
    await withApp(async app => {
      const cookie = await login(app);
      const endpoint = await app.inject({
        method: "POST",
        url: "/api/integrations/webhooks",
        headers: { cookie },
        payload: {
          name: "HayHashvapah connector",
          url: receiver.url,
          secret: "whsec-quote-test",
          events: ["quote_accepted", "deal_won", "invoice_paid"],
          enabled: true
        }
      });
      assert.equal(endpoint.statusCode, 200, endpoint.body);
      assert.equal(endpoint.json().endpoint.secretPreview, "whse...test");
      assert.equal(endpoint.json().endpoint.secret, undefined);

      const accepted = await app.inject({
        method: "POST",
        url: "/api/public/quotes/public-quote-ani-inbox-token/accept",
        payload: {
          signerName: "Ani Owner",
          signerEmail: "owner@anibeauty.am",
          acceptedAt: "2026-05-26"
        }
      });
      assert.equal(accepted.statusCode, 200, accepted.body);

      assert.equal(receiver.requests.length, 2);
      const events = receiver.requests.map(request => request.json.event).sort();
      assert.deepEqual(events, ["deal_won", "quote_accepted"]);
      for (const request of receiver.requests) {
        assert.equal(request.method, "POST");
        assert.equal(request.headers["x-armosphera-event"].startsWith("quote_") || request.headers["x-armosphera-event"] === "deal_won", true);
        assert.equal(request.headers["x-armosphera-signature"], signatureFor("whsec-quote-test", request.rawBody));
        assert.equal(request.json.product, "Armosphera One");
        assert.equal(request.json.organization.id, "org-armosphera-demo");
        assert.equal(request.json.customer.id, "cust-ani");
      }

      const deliveries = await app.inject({ method: "GET", url: "/api/integrations/webhook-deliveries", headers: { cookie } });
      assert.equal(deliveries.statusCode, 200, deliveries.body);
      assert.equal(deliveries.json().deliveries.filter(delivery => delivery.status === "succeeded").length, 2);

      const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
      assert.ok(audit.json().events.some(event => event.type === "webhook.delivery.succeeded"));
    });
  });
});

