test("analytics semantic metrics expose definitions and drilldowns with role access", async () => {
  await withApp(async app => {
    const accountantCookie = await login(app, "accountant@armosphera.local");
    const supportCookie = await login(app, "support@armosphera.local");

    const denied = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-metrics",
      headers: { cookie: supportCookie }
    });
    assert.equal(denied.statusCode, 403);

    const response = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-metrics",
      headers: { cookie: accountantCookie }
    });
    assert.equal(response.statusCode, 200, response.body);
    const body = response.json();
    assert.equal(body.semanticLayerVersion, "2026-05-27");
    assert.ok(body.generatedAt);
    assert.ok(body.metrics.length >= 8);

    const ids = body.metrics.map(metric => metric.id);
    for (const id of [
      "pipeline-value",
      "forecast-weighted",
      "campaign-roi",
      "receivables-aging",
      "overdue-exposure",
      "ticket-backlog",
      "sla-risk",
      "vat-readiness"
    ]) {
      assert.ok(ids.includes(id), `missing ${id}`);
    }

    const overdue = body.metrics.find(metric => metric.id === "overdue-exposure");
    assert.equal(overdue.unit, "AMD");
    assert.equal(overdue.value, 960000);
    assert.equal(overdue.sourceApps.includes("HayHashvapah Finance"), true);
    assert.ok(overdue.formula.includes("Open invoice total"));
    assert.ok(overdue.definition.includes("overdue"));
    assert.equal(overdue.drilldownUrl, "/api/analytics/semantic-metrics/overdue-exposure/drilldown");

    const sla = body.metrics.find(metric => metric.id === "sla-risk");
    assert.equal(sla.value, 1);
    assert.ok(sla.sourceApps.includes("Armosphera Desk"));

    const vat = body.metrics.find(metric => metric.id === "vat-readiness");
    assert.equal(vat.unit, "status-count");
    assert.ok(vat.value >= 1);
    assert.ok(vat.sourceApps.includes("Armenian localization"));

    const overdueDrilldown = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-metrics/overdue-exposure/drilldown",
      headers: { cookie: accountantCookie }
    });
    assert.equal(overdueDrilldown.statusCode, 200, overdueDrilldown.body);
    const overdueBody = overdueDrilldown.json();
    assert.equal(overdueBody.metric.id, "overdue-exposure");
    assert.ok(overdueBody.records.some(record =>
      record.sourceApp === "HayHashvapah Finance"
        && record.invoiceId === "inv-1007"
        && record.invoiceNumber === "HHV-1007"
        && record.daysPastDue === 6
        && record.total === 960000
    ));
    assert.equal(overdueBody.totals.recordCount, overdueBody.records.length);

    const slaDrilldown = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-metrics/sla-risk/drilldown",
      headers: { cookie: accountantCookie }
    });
    assert.equal(slaDrilldown.statusCode, 200, slaDrilldown.body);
    assert.ok(slaDrilldown.json().records.some(record =>
      record.sourceApp === "Armosphera Desk"
        && record.caseNumber === "AO-CASE-1001"
        && record.slaStatus === "at-risk"
    ));

    const unknown = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-metrics/unknown/drilldown",
      headers: { cookie: accountantCookie }
    });
    assert.equal(unknown.statusCode, 404);

    const analytics = await app.inject({ method: "GET", url: "/api/analytics", headers: { cookie: accountantCookie } });
    assert.equal(analytics.statusCode, 200, analytics.body);
    assert.ok(analytics.json().semanticMetrics.some(metric => metric.id === "overdue-exposure"));
  });
});

test("analytics semantic snapshots persist time-series with writer controls and backup scope", async () => {
  await withApp(async app => {
    const accountantCookie = await login(app, "accountant@armosphera.local");
    const auditorCookie = await login(app, "auditor@armosphera.local");
    const supportCookie = await login(app, "support@armosphera.local");
    const ownerCookie = await login(app);

    const supportDenied = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-snapshots",
      headers: { cookie: supportCookie }
    });
    assert.equal(supportDenied.statusCode, 403);

    const auditorWriteDenied = await app.inject({
      method: "POST",
      url: "/api/analytics/semantic-snapshots",
      headers: { cookie: auditorCookie },
      payload: { reportDate: "2026-05-26", note: "Auditor cannot capture analytics snapshots" }
    });
    assert.equal(auditorWriteDenied.statusCode, 403);

    const firstCapture = await app.inject({
      method: "POST",
      url: "/api/analytics/semantic-snapshots",
      headers: { cookie: accountantCookie },
      payload: { reportDate: "2026-05-26", note: "Daily owner and accountant metric close" }
    });
    assert.equal(firstCapture.statusCode, 200, firstCapture.body);
    const firstBody = firstCapture.json();
    assert.equal(firstBody.snapshotRun.reportDate, "2026-05-26");
    assert.equal(firstBody.snapshotRun.metricCount, 8);
    assert.equal(firstBody.snapshotRun.createdCount, 8);
    assert.equal(firstBody.snapshotRun.updatedCount, 0);
    assert.match(firstBody.snapshotRun.checksum, /^[a-f0-9]{64}$/);
    assert.equal(firstBody.snapshots.length, 8);

    const overdueSnapshot = firstBody.snapshots.find(snapshot => snapshot.metricId === "overdue-exposure");
    assert.equal(overdueSnapshot.value, 960000);
    assert.equal(overdueSnapshot.unit, "AMD");
    assert.equal(overdueSnapshot.recordCount, 1);
    assert.ok(overdueSnapshot.sourceApps.includes("HayHashvapah Finance"));
    assert.ok(overdueSnapshot.formula.includes("Open invoice total"));
    assert.match(overdueSnapshot.checksum, /^[a-f0-9]{64}$/);

    const repeatedCapture = await app.inject({
      method: "POST",
      url: "/api/analytics/semantic-snapshots",
      headers: { cookie: accountantCookie },
      payload: { reportDate: "2026-05-26", note: "Refresh same reporting day" }
    });
    assert.equal(repeatedCapture.statusCode, 200, repeatedCapture.body);
    assert.equal(repeatedCapture.json().snapshotRun.createdCount, 0);
    assert.equal(repeatedCapture.json().snapshotRun.updatedCount, 8);

    const nextDayCapture = await app.inject({
      method: "POST",
      url: "/api/analytics/semantic-snapshots",
      headers: { cookie: accountantCookie },
      payload: { reportDate: "2026-05-27", note: "Next reporting day" }
    });
    assert.equal(nextDayCapture.statusCode, 200, nextDayCapture.body);
    assert.equal(nextDayCapture.json().snapshotRun.createdCount, 8);

    const series = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-snapshots?metricId=overdue-exposure",
      headers: { cookie: auditorCookie }
    });
    assert.equal(series.statusCode, 200, series.body);
    const seriesBody = series.json();
    assert.equal(seriesBody.snapshots.length, 2);
    assert.equal(seriesBody.series.length, 1);
    assert.equal(seriesBody.series[0].metricId, "overdue-exposure");
    assert.deepEqual(seriesBody.series[0].points.map(point => point.reportDate), ["2026-05-26", "2026-05-27"]);
    assert.ok(seriesBody.series[0].points.every(point => point.value === 960000));

    const allSnapshots = await app.inject({
      method: "GET",
      url: "/api/analytics/semantic-snapshots",
      headers: { cookie: accountantCookie }
    });
    assert.equal(allSnapshots.statusCode, 200, allSnapshots.body);
    assert.equal(allSnapshots.json().snapshots.length, 16);
    assert.ok(allSnapshots.json().series.some(item => item.metricId === "sla-risk" && item.points.length === 2));

    const analytics = await app.inject({ method: "GET", url: "/api/analytics", headers: { cookie: accountantCookie } });
    assert.equal(analytics.statusCode, 200, analytics.body);
    assert.ok(analytics.json().semanticSnapshots.series.some(item => item.metricId === "overdue-exposure"));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: ownerCookie },
      payload: { note: "Semantic analytics snapshots are included in tenant backup scope." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.analytics_metric_snapshots.some(snapshot => snapshot.metric_id === "overdue-exposure"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => event.type === "analytics.semantic_snapshot.captured" && event.details.reportDate === "2026-05-26"));
  });
});

