    const listed = await app.inject({ method: "GET", url: "/api/finance/bank-transactions?customerId=cust-nare", headers: { cookie } });
    assert.equal(listed.statusCode, 200, listed.body);
    assert.ok(listed.json().transactions.some(transaction => transaction.id === body.transaction.id && transaction.status === "reconciled"));

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie } });
    assert.equal(customer360.statusCode, 200, customer360.body);
    const customer = customer360.json();
