async function createReleasedClinicPilotQuote(app) {
  const ownerCookie = await login(app);
  const salespersonCookie = await login(app, "sales@armosphera.local");
  const operatorCookie = await login(app, "operator@armosphera.local");
  const accountantCookie = await login(app, "accountant@armosphera.local");
  const supportCookie = await login(app, "support@armosphera.local");

  const installed = await app.inject({
    method: "POST",
    url: "/api/pilots/templates/clinic-wellness/install",
    headers: { cookie: ownerCookie },
    payload: {
      customerId: "cust-nare",
      selectedPackageKeys: ["patient-retention", "booking-inbox", "receivables-handoff"],
      pilotCount: 5
    }
  });
  assert.equal(installed.statusCode, 200, installed.body);

  const briefResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/owner-briefs",
    headers: { cookie: ownerCookie },
    payload: { installId: installed.json().install.id, reportDate: "2026-05-27" }
  });
  assert.equal(briefResponse.statusCode, 200, briefResponse.body);

  const workbenchResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/operator-workbenches",
    headers: { cookie: operatorCookie },
    payload: { briefId: briefResponse.json().brief.id }
  });
  assert.equal(workbenchResponse.statusCode, 200, workbenchResponse.body);

  const reviewResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/accountant-reviews",
    headers: { cookie: accountantCookie },
    payload: { workbenchId: workbenchResponse.json().workbench.id }
  });
  assert.equal(reviewResponse.statusCode, 200, reviewResponse.body);

  const readinessResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/launch-readiness",
    headers: { cookie: ownerCookie },
    payload: { accountantReviewId: reviewResponse.json().review.id, targetLaunchDate: "2026-06-03" }
  });
  assert.equal(readinessResponse.statusCode, 200, readinessResponse.body);

  const planResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/launch-remediation-plans",
    headers: { cookie: ownerCookie },
    payload: { launchReadinessId: readinessResponse.json().packet.id }
  });
  assert.equal(planResponse.statusCode, 200, planResponse.body);
  const plan = planResponse.json().plan;

  for (const action of plan.payload.actions) {
    const actorCookie = action.ownerRole === "Accountant"
      ? accountantCookie
      : action.ownerRole === "Operator"
        ? operatorCookie
        : ownerCookie;
    const resolved = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/remediation-actions/${action.key}/resolve`,
      headers: { cookie: actorCookie },
      payload: {
        planId: plan.id,
        evidenceType: `${action.category || action.sourceGate}-acceptance-handoff`,
        evidence: `${action.title} resolved before accepted quote accounting handoff.`
      }
    });
    assert.equal(resolved.statusCode, 200, resolved.body);
  }

  const clearanceResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/launch-clearance",
    headers: { cookie: ownerCookie },
    payload: { remediationPlanId: plan.id }
  });
  assert.equal(clearanceResponse.statusCode, 200, clearanceResponse.body);

  const offerResponse = await app.inject({
    method: "POST",
    url: "/api/pilots/clinic-wellness/paid-offers",
    headers: { cookie: salespersonCookie },
    payload: {
      clearancePacketId: clearanceResponse.json().packet.id,
      validUntil: "2026-06-10"
    }
  });
  assert.equal(offerResponse.statusCode, 200, offerResponse.body);
  const offer = offerResponse.json().offer;

  const handoffResponse = await app.inject({
    method: "POST",
    url: `/api/pilots/clinic-wellness/paid-offers/${offer.id}/quote-handoff`,
    headers: { cookie: salespersonCookie },
    payload: {
      dealId: "deal-nare-retainer",
      validUntil: "2026-06-17",
      note: "Create governed CRM quote from the paid pilot offer."
    }
  });
  assert.equal(handoffResponse.statusCode, 200, handoffResponse.body);
  const handoff = handoffResponse.json().handoff;
  const quote = handoffResponse.json().quote;
  const approval = handoffResponse.json().approval;

  const decision = await app.inject({
    method: "POST",
    url: `/api/workflow/approvals/${approval.id}/decision`,
    headers: { cookie: ownerCookie },
    payload: { decision: "approved", note: "Owner approved pilot quote release." }
  });
  assert.equal(decision.statusCode, 200, decision.body);

  const execution = await app.inject({
    method: "POST",
    url: `/api/workflow/approvals/${approval.id}/execute`,
    headers: { cookie: ownerCookie }
  });
  assert.equal(execution.statusCode, 200, execution.body);

  const releaseResponse = await app.inject({
    method: "POST",
    url: `/api/pilots/clinic-wellness/quote-handoffs/${handoff.id}/release-packet`,
    headers: { cookie: salespersonCookie },
    payload: { note: "Pilot quote public release evidence." }
  });
  assert.equal(releaseResponse.statusCode, 200, releaseResponse.body);

  return {
    ownerCookie,
    salespersonCookie,
    accountantCookie,
    supportCookie,
    offer,
    handoff,
    quote,
    quoteReleaseApproval: approval,
    releasePacket: releaseResponse.json().packet
  };
}

