async function createPilotSubsequentRenewalHayhashvapahDraftPacket(app) {
  const proof = await createPilotSubsequentRenewalAcceptanceHandoff(app);

  const decision = await app.inject({
    method: "POST",
    url: `/api/workflow/approvals/${proof.subsequentRenewalFinanceApproval.id}/decision`,
    headers: { cookie: proof.ownerCookie },
    payload: { decision: "approved", note: "Owner approved subsequent monthly renewal HayHashvapah draft invoice creation." }
  });
  assert.equal(decision.statusCode, 200, decision.body);

  let execution = await app.inject({
    method: "POST",
    url: `/api/workflow/approvals/${proof.subsequentRenewalFinanceApproval.id}/execute`,
    headers: { cookie: proof.ownerCookie }
  });
  if (execution.statusCode === 409) {
    assert.equal(execution.json().error, "PERIOD_LOCKED");
    assert.equal(execution.json().retry.available, true);
    const reopened = await app.inject({
      method: "POST",
      url: "/api/finance/periods/2026-08/reopen",
      headers: { cookie: proof.ownerCookie }
    });
    assert.equal(reopened.statusCode, 200, reopened.body);
    execution = await app.inject({
      method: "POST",
      url: execution.json().retry.endpoint,
      headers: { cookie: proof.ownerCookie }
    });
  }
  assert.equal(execution.statusCode, 200, execution.body);

  const draftPacketResponse = await app.inject({
    method: "POST",
    url: `/api/pilots/clinic-wellness/subsequent-renewal-acceptance-handoffs/${proof.subsequentRenewalAcceptanceHandoff.id}/draft-invoice-packet`,
    headers: { cookie: proof.accountantCookie },
    payload: { note: "Subsequent renewal HayHashvapah draft invoice is ready for official posting review." }
  });
  assert.equal(draftPacketResponse.statusCode, 200, draftPacketResponse.body);
  return {
    ...proof,
    subsequentRenewalDraftInvoice: execution.json().draftInvoice,
    subsequentRenewalDraftWorkflowRun: execution.json().run,
    subsequentRenewalDraftPacket: draftPacketResponse.json().packet
  };
}

