async function withWebhookReceiver(fn) {
  const receiver = {
    requests: [],
    statusCode: 200,
    url: ""
  };
  const server = http.createServer((request, response) => {
    let rawBody = "";
    request.setEncoding("utf8");
    request.on("data", chunk => { rawBody += chunk; });
    request.on("end", () => {
      receiver.requests.push({
        method: request.method,
        url: request.url,
        headers: request.headers,
        rawBody,
        json: JSON.parse(rawBody || "{}")
      });
      response.statusCode = receiver.statusCode;
      response.setHeader("content-type", "application/json");
      response.end(JSON.stringify({ ok: receiver.statusCode < 400 }));
    });
  });
  await new Promise(resolve => server.listen(0, "127.0.0.1", resolve));
  const address = server.address();
  receiver.url = `http://127.0.0.1:${address.port}/webhook`;
  try {
    await fn(receiver);
  } finally {
    await new Promise(resolve => server.close(resolve));
  }
}

function signatureFor(secret, rawBody) {
  return `sha256=${crypto.createHmac("sha256", secret).update(rawBody).digest("hex")}`;
}

function sha256(value) {
  return crypto.createHash("sha256").update(value).digest("hex");
}
